# ------------------------------------------------------------------
# 한글 폰트 설정
# (Noto Sans CJK 같은 TTC 컬렉션 폰트는 matplotlib이 내부 서브폰트를
#  제대로 못 찾는 경우가 많아, 시스템에 설치된 한글 폰트 후보를
#  순서대로 찾아 등록한다. 환경에 맞는 폰트가 있으면 그걸 쓰고,
#  없으면 마이너스 기호 깨짐만 방지한다.)
# ------------------------------------------------------------------
def _setup_korean_font():
    candidates = [
        "Malgun Gothic",      # Windows
        "AppleGothic",        # macOS
        "NanumGothic",        # Linux (나눔고딕 설치 시)
        "Noto Sans CJK KR",   # Linux (서브셋 추출 필요할 수 있음)
        "Noto Sans KR",
    ]
    available = {f.name for f in fm.fontManager.ttflist}
    for name in candidates:
        if name in available:
            mpl.rc("font", family=name)
            break
    else:
        # TTC 컬렉션에서 KR 서브폰트만 추출해 등록 시도 (Linux 환경 대비)
        import glob
        registered = False
        for ttc_path in glob.glob("/usr/share/fonts/**/NotoSansCJK*.ttc", recursive=True):
            try:
                from fontTools.ttLib import TTCollection
                tc = TTCollection(ttc_path)
                for sub in tc.fonts:
                    if sub["name"].getDebugName(1) == "Noto Sans CJK KR":
                        out_path = "/tmp/NotoSansCJKkr-Regular.ttf"
                        sub.save(out_path)
                        fm.fontManager.addfont(out_path)
                        mpl.rc("font", family="Noto Sans CJK KR")
                        registered = True
                        break
            except Exception:
                continue
            if registered:
                break

    mpl.rcParams["axes.unicode_minus"] = False  # 마이너스(-) 기호 깨짐 방지


_setup_korean_font()


