# 문제별 학생 정오답 분포
# ------------------------------------------------------------------
def students_each_prob_graph(datalist, cname, aname):
    problem_attempt_count = {}
    problem_correct_count = {}

    for code_index, data_list in enumerate(datalist):
        problem_attempt_count[code_index] = {}
        problem_correct_count[code_index] = {}

        for data in data_list:
            student_num = data["suid"]

            if student_num in problem_attempt_count[code_index]:
                problem_attempt_count[code_index][student_num] += 1
            else:
                problem_attempt_count[code_index][student_num] = 1

            if data["result"] == "Accept":
                problem_correct_count[code_index][student_num] = 1

    sorted_problem_counts = sorted(problem_attempt_count.items(), key=lambda x: x[0])
    sorted_correct_counts = sorted(problem_correct_count.items(), key=lambda x: x[0])

    problem_indices = [idx for idx, _ in sorted_problem_counts]
    student_counts = [sum(counts.values()) for _, counts in sorted_problem_counts]
    correct_counts = [sum(counts.values()) for _, counts in sorted_correct_counts]

    # 사람이 읽기 좋은 1-indexed 라벨 ("문제 1", "문제 2", ...)
    x_labels = [f"문제 {i+1}" for i in problem_indices]
    x = np.arange(len(problem_indices))
    bar_width = 0.38

    fig, ax = plt.subplots(figsize=(max(6, len(x) * 1.3), 6))

    bars_attempt = ax.bar(
        x - bar_width / 2, student_counts, width=bar_width,
        label="시도한 학생 수", color="#4C72B0"
    )
    bars_correct = ax.bar(
        x + bar_width / 2, correct_counts, width=bar_width,
        label="정답자 수", color="#DD8452"
    )

    def _annotate(bars):
        for rect in bars:
            height = rect.get_height()
            ax.annotate(
                f"{int(height)}",
                xy=(rect.get_x() + rect.get_width() / 2, height),
                xytext=(0, 3),
                textcoords="offset points",
                ha="center", va="bottom", fontsize=11,
            )

    _annotate(bars_attempt)
    _annotate(bars_correct)

    ax.set_xticks(x)
    ax.set_xticklabels(x_labels)
    ax.set_xlabel("문제 번호")
    ax.set_ylabel("학생 수")
    ax.set_title(f"{cname} {aname}의 각 문제를 시도한 학생 수")
    ax.set_ylim(0, max(student_counts) * 1.15 if student_counts else 1)
    ax.legend()
    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)

    fig.tight_layout()
    plt.show()


# ------------------------------------------------------------------
# 응시자 총 점수 분포 (이산 카테고리 막대그래프)
# ------------------------------------------------------------------
def score_distribution_graph(trialdata, cname, aname, totalscores_fn):
    score_counts = totalscores_fn(trialdata)

    # 점수가 너무 잘게 쪼개져 있으면(소수점 등) 그대로 막대로 그리면
    # 라벨이 다닥다닥 겹친다. 고유 점수 종류가 많을 때는 자동으로
    # 히스토그램(구간 묶기) 방식으로 전환한다.
    unique_scores = sorted(score_counts.keys())
    n_unique = len(unique_scores)

    fig, ax = plt.subplots(figsize=(10, 6))

    if n_unique > 25:
        # 막대 종류가 너무 많음 -> 구간을 묶어서 히스토그램으로 표현
        raw_scores = []
        for score, cnt in score_counts.items():
            raw_scores.extend([score] * cnt)

        bins = min(20, n_unique)
        counts, edges, patches = ax.hist(
            raw_scores, bins=bins, edgecolor="black", color="#4C72B0"
        )
        for count, left, right in zip(counts, edges[:-1], edges[1:]):
            if count > 0:
                ax.text(
                    (left + right) / 2, count, f"{int(count)}",
                    ha="center", va="bottom", fontsize=10,
                )
        ax.set_xlabel("점수 구간")
    else:
        # 막대 종류가 적당함 -> 카테고리 막대그래프
        x_pos = np.arange(n_unique)
        heights = [score_counts[s] for s in unique_scores]
        bars = ax.bar(x_pos, heights, color="#4C72B0", width=0.6)
        ax.set_xticks(x_pos)
        ax.set_xticklabels([f"{s:g}" for s in unique_scores], rotation=0)
        for rect in bars:
            height = rect.get_height()
            ax.annotate(
                f"{int(height)}",
                xy=(rect.get_x() + rect.get_width() / 2, height),
                xytext=(0, 3),
                textcoords="offset points",
                ha="center", va="bottom", fontsize=11,
            )
        ax.set_xlabel("점수")

    ax.set_ylabel("학생 수")
    ax.set_title(f"{cname} {aname}의 점수 분포표")
    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)

    fig.tight_layout()
    plt.show()


# ------------------------------------------------------------------
# 응시자 총 점수 분포 (상위 n% 하이라이트)
# ------------------------------------------------------------------
def total_score_graph(trialdata, cname, aname):
    graphthick = 30   # 히스토그램 구간 수
    toppercent = 20   # 상위 퍼센트 하이라이트
    title_text = f"{cname} {aname} 응시자의 총 점수 분포 (상위 {toppercent}%)"

    total_scores = [data["총점"] for data in trialdata]
    total_students = len(total_scores)

    fig, ax = plt.subplots(figsize=(9, 5.5))

    counts, edges, patches = ax.hist(
        total_scores, bins=graphthick, edgecolor="black", color="#4C72B0"
    )

    # y축 눈금을 데이터에 맞춰 동적으로 설정 (하드코딩된 0~9 범위 제거)
    max_count = int(counts.max()) if len(counts) else 0
    step = max(1, round(max_count / 10))
    ax.set_yticks(np.arange(0, max_count + step, step))

    ax.set_xlabel("총점")
    ax.set_ylabel("학생 수")
    ax.set_title(title_text)
    ax.text(
        0.02, 0.96, f"학생 수: {total_students}",
        transform=ax.transAxes, va="top", fontsize=11,
        bbox=dict(boxstyle="round", facecolor="white", alpha=0.7, edgecolor="none"),
    )

    total_scores_np = np.array(total_scores)
    threshold = np.percentile(total_scores_np, 100 - toppercent)
    ax.axvspan(threshold, np.max(total_scores_np), color="orange", alpha=0.3,
               label=f"상위 {toppercent}% (≥ {threshold:.1f}점)")
    ax.legend(loc="upper left", bbox_to_anchor=(0.02, 0.86), frameon=False, fontsize=10)

    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)

    fig.tight_layout()
    plt.show()

