import datetime

# 현재 시간을 "YYYYMMDD_HHMMSS" 형식으로 생성
now_str = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")

# 파일명에 사용할 수 없는 문자 제거 (윈도우 기준: \ / : * ? " < > |)
def sanitize_filename(name):
    for ch in r'\/:*?"<>|':
        name = name.replace(ch, "_")
    return name

safe_course_name = sanitize_filename(course_name)
safe_assignment_name = sanitize_filename(assignment_name)

# 파일명 생성: [과목명]_[시험명]_결과_[시간].txt
filename = f"{safe_course_name}_{safe_assignment_name}_결과_{now_str}.txt"

# datalist 내용을 텍스트 파일로 저장
with open(filename, "w", encoding="utf-8") as f:
    for prob_idx, data_list in enumerate(datalist):
        f.write(f"[문제 {prob_idx + 1}]\n")
        for entry in data_list:
            suid = entry.get("suid")
            result = entry.get("result")
            score = entry.get("score")
            f.write(f"학번: {suid}, 결과: {result}, 점수: {score}\n")
        f.write("\n")

print(f"결과가 '{filename}' 파일로 저장되었습니다.")

